import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";
import { listRunHistories } from "@/lib/run-history-manager";

export async function GET(request: NextRequest) {
  try {
    const scenarioId = request.nextUrl.searchParams.get("scenarioId") ?? undefined;
    const data = listRunHistories(scenarioId);
    return NextResponse.json({ success: true, data });
  } catch (error) {
    return NextResponse.json({ success: false, error: String(error) }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";
import { getRunHistory, deleteRunHistory } from "@/lib/run-history-manager";

export async function GET(_: NextRequest, { params }: { params: { id: string } }) {
  const run = getRunHistory(params.id);

  if (!run) {
    return NextResponse.json({ success: false, error: "Not found" }, { status: 404 });
  }

  return NextResponse.json({ success: true, data: run });
}

export async function DELETE(_: NextRequest, { params }: { params: { id: string } }) {
  const deleted = deleteRunHistory(params.id);

  if (!deleted) {
    return NextResponse.json({ success: false, error: "Not found" }, { status: 404 });
  }

  return NextResponse.json({ success: true });
}

